import time

class MiniRedisDB:
    def __init__(self):
        self.db = {}  # key -> {"type":str, "value":..., "expiry":float or None}

    def _now(self):
        return time.time()

    def _clean_expired(self):
        to_del = [k for k, v in self.db.items() if v["expiry"] is not None and self._now() >= v["expiry"]]
        for k in to_del:
            del self.db[k]

    def _get_key(self, key):
        if key in self.db:
            entry = self.db[key]
            if entry["expiry"] is not None and self._now() >= entry["expiry"]:
                del self.db[key]
                return None
            return entry
        return None

    def set(self, key, value):
        # Overwrite any type
        self.db[key] = {"type": "string", "value": str(value), "expiry": None}
        return "OK"

    def get(self, key):
        entry = self._get_key(key)
        if entry is None:
            return "(nil)"
        if entry["type"] != "string":
            raise CommandError("WRONGTYPE Operation against a key holding the wrong kind of value")
        return entry["value"]

    def delete(self, *keys):
        count = 0
        for key in keys:
            entry = self._get_key(key)
            if entry is not None:
                del self.db[key]
                count += 1
        return count

    def exists(self, key):
        entry = self._get_key(key)
        return 1 if entry is not None else 0

    def lpush(self, key, *elements):
        entry = self._get_key(key)
        if entry is None:
            # create
            entry = {"type": "list", "value": [], "expiry": None}
            self.db[key] = entry
        elif entry["type"] != "list":
            raise CommandError("WRONGTYPE Operation against a key holding the wrong kind of value")
        lst = entry["value"]
        # prepend each element in order provided
        for e in reversed(elements):
            lst.insert(0, e)
        return len(lst)

    def rpush(self, key, *elements):
        entry = self._get_key(key)
        if entry is None:
            entry = {"type": "list", "value": [], "expiry": None}
            self.db[key] = entry
        elif entry["type"] != "list":
            raise CommandError("WRONGTYPE Operation against a key holding the wrong kind of value")
        lst = entry["value"]
        lst.extend(elements)
        return len(lst)

    def lpop(self, key):
        entry = self._get_key(key)
        if entry is None:
            return "(nil)"
        if entry["type"] != "list":
            raise CommandError("WRONGTYPE Operation against a key holding the wrong kind of value")
        lst = entry["value"]
        if not lst:
            # empty list, auto-delete
            del self.db[key]
            return "(nil)"
        val = lst.pop(0)
        if not lst:
            del self.db[key]
        return val

    def rpop(self, key):
        entry = self._get_key(key)
        if entry is None:
            return "(nil)"
        if entry["type"] != "list":
            raise CommandError("WRONGTYPE Operation against a key holding the wrong kind of value")
        lst = entry["value"]
        if not lst:
            del self.db[key]
            return "(nil)"
        val = lst.pop()
        if not lst:
            del self.db[key]
        return val

    def lrange(self, key, start, stop):
        entry = self._get_key(key)
        if entry is None:
            return "[]"
        if entry["type"] != "list":
            raise CommandError("WRONGTYPE Operation against a key holding the wrong kind of value")
        lst = entry["value"]
        length = len(lst)
        if length == 0:
            return "[]"
        start = int(start)
        stop = int(stop)
        # adjust
        if start < 0:
            start += length
        if start < 0:
            start = 0
        if stop < 0:
            stop += length
        if stop < 0:
            stop = 0
        if start > length - 1 or start > stop:
            return "[]"
        if stop > length - 1:
            stop = length - 1
        sliced = lst[start:stop+1]
        return json.dumps(sliced, separators=(',', ':'))

    def llen(self, key):
        entry = self._get_key(key)
        if entry is None:
            return 0
        if entry["type"] != "list":
            raise CommandError("WRONGTYPE Operation against a key holding the wrong kind of value")
        return len(entry["value"])

    def sadd(self, key, *members):
        entry = self._get_key(key)
        if entry is None:
            entry = {"type": "set", "value": set(), "expiry": None}
            self.db[key] = entry
        elif entry["type"] != "set":
            raise CommandError("WRONGTYPE Operation against a key holding the wrong kind of value")
        s = entry["value"]
        added = 0
        for m in members:
            if m not in s:
                s.add(m)
                added += 1
        return added

    def srem(self, key, *members):
        entry = self._get_key(key)
        if entry is None:
            return 0  # key doesn't exist, nothing removed
        if entry["type"] != "set":
            raise CommandError("WRONGTYPE Operation against a key holding the wrong kind of value")
        s = entry["value"]
        removed = 0
        for m in members:
            if m in s:
                s.remove(m)
                removed += 1
        if not s:
            del self.db[key]  # auto-delete empty set
        return removed

    def smembers(self, key):
        entry = self._get_key(key)
        if entry is None:
            return "[]"
        if entry["type"] != "set":
            raise CommandError("WRONGTYPE Operation against a key holding the wrong kind of value")
        members = sorted(entry["value"])
        return json.dumps(members, separators=(',', ':'))

    def sismember(self, key, member):
        entry = self._get_key(key)
        if entry is None:
            return 0
        if entry["type"] != "set":
            raise CommandError("WRONGTYPE Operation against a key holding the wrong kind of value")
        return 1 if member in entry["value"] else 0

    def scard(self, key):
        entry = self._get_key(key)
        if entry is None:
            return 0
        if entry["type"] != "set":
            raise CommandError("WRONGTYPE Operation against a key holding the wrong kind of value")
        return len(entry["value"])

    def hset(self, key, *pairs):
        if len(pairs) % 2 != 0:
            raise CommandError("wrong number of arguments for HSET")
        entry = self._get_key(key)
        if entry is None:
            entry = {"type": "hash", "value": {}, "expiry": None}
            self.db[key] = entry
        elif entry["type"] != "hash":
            raise CommandError("WRONGTYPE Operation against a key holding the wrong kind of value")
        h = entry["value"]
        new_count = 0
        for i in range(0, len(pairs), 2):
            field = pairs[i]
            value = pairs[i+1]
            if field not in h:
                new_count += 1
            h[field] = value
        return new_count

    def hget(self, key, field):
        entry = self._get_key(key)
        if entry is None:
            return "(nil)"
        if entry["type"] != "hash":
            raise CommandError("WRONGTYPE Operation against a key holding the wrong kind of value")
        h = entry["value"]
        return h.get(field, "(nil)")

    def hdel(self, key, *fields):
        entry = self._get_key(key)
        if entry is None:
            return 0
        if entry["type"] != "hash":
            raise CommandError("WRONGTYPE Operation against a key holding the wrong kind of value")
        h = entry["value"]
        removed = 0
        for f in fields:
            if f in h:
                del h[f]
                removed += 1
        if not h:
            del self.db[key]
        return removed

    def hgetall(self, key):
        entry = self._get_key(key)
        if entry is None:
            return "{}"
        if entry["type"] != "hash":
            raise CommandError("WRONGTYPE Operation against a key holding the wrong kind of value")
        return json.dumps(entry["value"], separators=(',', ':'))

    def hexists(self, key, field):
        entry = self._get_key(key)
        if entry is None:
            return 0
        if entry["type"] != "hash":
            raise CommandError("WRONGTYPE Operation against a key holding the wrong kind of value")
        return 1 if field in entry["value"] else 0

    def keys(self, pattern=None):
        self._clean_expired()  # remove expired before listing
        all_keys = list(self.db.keys())
        if pattern is None:
            matched = all_keys
        else:
            matched = [k for k in all_keys if fnmatch.fnmatch(k, pattern)]
        matched.sort()
        return json.dumps(matched, separators=(',', ':'))

    def type(self, key):
        entry = self._get_key(key)
        if entry is None:
            return "none"
        return entry["type"]

    def expire(self, key, seconds):
        entry = self._get_key(key)
        if entry is None:
            return 0
        entry["expiry"] = self._now() + int(seconds)
        return 1

    def ttl(self, key):
        entry = self._get_key(key)
        if entry is None:
            return -2
        if entry["expiry"] is None:
            return -1
        remaining = int(entry["expiry"] - self._now())
        if remaining < 0:
            # expired, should delete lazily, but TTL should return -2
            del self.db[key]
            return -2
        return remaining

    def flushdb(self):
        self.db.clear()
        return "OK"

    def dbsize(self):
        self._clean_expired()
        return len(self.db)
